import java.util.LinkedList

class StrandSort {
    fun sort(arr: IntArray) {
        if (arr.size <= 1) return

        val list = LinkedList<Int>()
        for (i in arr) list.add(i)

        var sorted = LinkedList<Int>()

        while (list.isNotEmpty()) {
            val strand = LinkedList<Int>()
            strand.add(list.removeFirst())

            val it = list.iterator()
            while (it.hasNext()) {
                val value = it.next()
                if (value >= strand.last) {
                    strand.add(value)
                    it.remove()
                }
            }

            sorted = merge(sorted, strand)
        }

        for (i in arr.indices) {
            arr[i] = sorted[i]
        }
    }

    private fun merge(sorted: LinkedList<Int>, strand: LinkedList<Int>): LinkedList<Int> {
        val result = LinkedList<Int>()
        while (sorted.isNotEmpty() && strand.isNotEmpty()) {
            if (sorted.first <= strand.first) {
                result.add(sorted.removeFirst())
            } else {
                result.add(strand.removeFirst())
            }
        }
        result.addAll(sorted)
        result.addAll(strand)
        return result
    }
}

def strand_sort(arr):
    if not arr:
        return arr

    items = arr[:]
    sorted_list = []

    while items:
        strand = [items.pop(0)]
        remaining = []

        for item in items:
            if item >= strand[-1]:
                strand.append(item)
            else:
                remaining.append(item)

        items = remaining
        sorted_list = merge(sorted_list, strand)

    # Copy back to original array
    for i in range(len(arr)):
        arr[i] = sorted_list[i]

    return arr

def merge(sorted_list, strand):
    result = []
    while sorted_list and strand:
        if sorted_list[0] <= strand[0]:
            result.append(sorted_list.pop(0))
        else:
            result.append(strand.pop(0))

    result.extend(sorted_list)
    result.extend(strand)
    return result

pub fn strand_sort(arr: &mut [i32]) {
    if arr.len() <= 1 {
        return;
    }

    let mut list: Vec<i32> = arr.to_vec();
    let mut sorted: Vec<i32> = Vec::new();

    while !list.is_empty() {
        let mut strand: Vec<i32> = Vec::new();
        let mut remaining: Vec<i32> = Vec::new();

        strand.push(list.remove(0));

        for &item in &list {
            if item >= *strand.last().unwrap() {
                strand.push(item);
            } else {
                remaining.push(item);
            }
        }

        list = remaining;
        sorted = merge(sorted, strand);
    }

    arr.copy_from_slice(&sorted);
}

fn merge(sorted: Vec<i32>, strand: Vec<i32>) -> Vec<i32> {
    let mut result = Vec::with_capacity(sorted.len() + strand.len());
    let mut i = 0;
    let mut j = 0;

    while i < sorted.len() && j < strand.len() {
        if sorted[i] <= strand[j] {
            result.push(sorted[i]);
            i += 1;
        } else {
            result.push(strand[j]);
            j += 1;
        }
    }

    while i < sorted.len() {
        result.push(sorted[i]);
        i += 1;
    }

    while j < strand.len() {
        result.push(strand[j]);
        j += 1;
    }

    result
}

object StrandSort {
  def sort(arr: Array[Int]): Unit = {
    if (arr.length <= 1) return

    var list = arr.toList
    var sorted = List[Int]()

    while (list.nonEmpty) {
      var strand = List(list.head)
      var remaining = List[Int]()

      for (item <- list.tail) {
        if (item >= strand.last) {
          strand = strand :+ item
        } else {
          remaining = remaining :+ item
        }
      }

      list = remaining
      sorted = merge(sorted, strand)
    }

    for (i <- arr.indices) {
      arr(i) = sorted(i)
    }
  }

  private def merge(left: List[Int], right: List[Int]): List[Int] = {
    (left, right) match {
      case (Nil, _) => right
      case (_, Nil) => left
      case (l :: ls, r :: rs) =>
        if (l <= r) l :: merge(ls, right)
        else r :: merge(left, rs)
    }
  }
}

class StrandSort {
    static func sort(_ arr: inout [Int]) {
        if arr.count <= 1 { return }

        var list = arr
        var sorted: [Int] = []

        while !list.isEmpty {
            var strand: [Int] = []
            strand.append(list.removeFirst())

            var i = 0
            while i < list.count {
                if list[i] >= strand.last! {
                    strand.append(list.remove(at: i))
                } else {
                    i += 1
                }
            }

            sorted = merge(sorted, strand)
        }

        arr = sorted
    }

    private static func merge(_ left: [Int], _ right: [Int]) -> [Int] {
        var result: [Int] = []
        var i = 0
        var j = 0

        while i < left.count && j < right.count {
            if left[i] <= right[j] {
                result.append(left[i])
                i += 1
            } else {
                result.append(right[j])
                j += 1
            }
        }

        while i < left.count {
            result.append(left[i])
            i += 1
        }

        while j < right.count {
            result.append(right[j])
            j += 1
        }

        return result
    }
}

export function strandSort(arr: number[]): number[] {
  if (arr.length <= 1) return arr;

  let list = [...arr];
  let sorted: number[] = [];

  while (list.length > 0) {
    const strand: number[] = [list.shift()!];
    const remaining: number[] = [];

    for (const item of list) {
      if (item >= strand[strand.length - 1]) {
        strand.push(item);
      } else {
        remaining.push(item);
      }
    }

    list = remaining;
    sorted = merge(sorted, strand);
  }

  // Copy back to original array (in-place modification simulation)
  for (let i = 0; i < arr.length; i++) {
    arr[i] = sorted[i];
  }

  return arr;
}

function merge(left: number[], right: number[]): number[] {
  const result: number[] = [];
  let i = 0;
  let j = 0;

  while (i < left.length && j < right.length) {
    if (left[i] <= right[j]) {
      result.push(left[i]);
      i++;
    } else {
      result.push(right[j]);
      j++;
    }
  }

  return result.concat(left.slice(i)).concat(right.slice(j));
}

function mergeSorted(a: number[], b: number[]): number[] {
    const result: number[] = [];
    let i = 0, j = 0;
    while (i < a.length && j < b.length) {
        if (a[i] <= b[j]) result.push(a[i++]);
        else result.push(b[j++]);
    }
    while (i < a.length) result.push(a[i++]);
    while (j < b.length) result.push(b[j++]);
    return result;
}

export function strandSort(arr: number[]): number[] {
    if (arr.length <= 1) return [...arr];

    const remaining = [...arr];
    let output: number[] = [];

    while (remaining.length > 0) {
        const strand: number[] = [remaining.shift()!];

        let i = 0;
        while (i < remaining.length) {
            if (remaining[i] >= strand[strand.length - 1]) {
                strand.push(remaining.splice(i, 1)[0]);
            } else {
                i++;
            }
        }

        output = mergeSorted(output, strand);
    }

    return output;
}
